import React, { useState, useEffect } from "react";
import dayjs from "dayjs";
import axios from "axios";
import Cookies from "js-cookie";
import { toast } from "react-toastify";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";
import { useNavigate } from "react-router-dom";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const commonGrid = {
  grid: { display: false, drawBorder: false },
  ticks: { font: { size: 11 } },
};

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function Dashboard() {
  const navigate = useNavigate();
  const currentYear = new Date().getFullYear();

  const [summaryCards, setSummaryCards] = useState({
    totalUsers: 0,
    totalClient: 0,
    totalRevenue: 0,
    totalSupportTickets: 0,
  });

  const [leadsData, setLeadsData] = useState({});
  const [paymentsData, setPaymentsData] = useState({});
  const [clientDataByYear, setClientDataByYear] = useState({});

  const [leadYear, setLeadYear] = useState(currentYear);
  const [paymentsYear, setPaymentsYear] = useState(currentYear);
  const [selectedMonth, setSelectedMonth] = useState("all");

  /* ================= FETCH DATA ================= */

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) {
      navigate("/");
      return;
    }

    const fetchSupports = async () => {
      try {
        const res = await axios.get(`${API_BASE_URL}/supports`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data.success) {
          setSummaryCards((prev) => ({
            ...prev,
            totalSupportTickets: res.data.toatlPendingCount || 0,
          }));
        }
      } catch (err) {
        toast.error(err.response?.data?.error || "Error fetching supports");
      }
    };

    const fetchPayments = async () => {
      try {
        const res = await axios.get(`${API_BASE_URL}/payments`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        if (res.data.success) {
          const paymentAgg = {};

          res.data.data.forEach((p) => {
            const month = dayjs(p.paymentDate).month() + 1;
            const year = dayjs(p.paymentDate).year();

            if (!paymentAgg[year]) paymentAgg[year] = {};
            if (!paymentAgg[year][month])
              paymentAgg[year][month] = { payments: 0 };

            paymentAgg[year][month].payments += Number(p.paidAmount);
          });

          setPaymentsData(paymentAgg);

          setSummaryCards((prev) => ({
            ...prev,
            totalRevenue: res.data.totalPaidAmount || 0,
          }));
        }
      } catch (err) {
        toast.error(err.response?.data?.error || "Error fetching payments");
      } finally {
        fetchSupports();
      }
    };

    const fetchLeads = async () => {
      try {
        const res = await axios.get(`${API_BASE_URL}/leadhistory`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        if (res.data.success) {
          const leads = res.data.data;

          setSummaryCards((prev) => ({
            ...prev,
            totalUsers: res.data.totalApprovedCount || 0,
            totalClient: res.data.totalClientsCount || 0,
          }));

          const leadAgg = {};
          const clientAgg = {};

          leads.forEach((lead) => {
            const month = dayjs(lead.createdAt).month() + 1;
            const year = dayjs(lead.createdAt).year();

            if (!leadAgg[year]) leadAgg[year] = {};
            if (!leadAgg[year][month]) {
              leadAgg[year][month] = {
                total: 0,
                approved: 0,
                duplicate: 0,
              };
            }

            leadAgg[year][month].total += 1;
            if (lead.leadType === "Approved")
              leadAgg[year][month].approved += 1;
            if (lead.leadType === "Duplicate")
              leadAgg[year][month].duplicate += 1;

            if (lead.status === "Client") {
              if (!clientAgg[year]) clientAgg[year] = {};
              if (!clientAgg[year][month]) clientAgg[year][month] = 0;
              clientAgg[year][month] += 1;
            }
          });

          setLeadsData(leadAgg);
          setClientDataByYear(clientAgg);
        }
      } catch (err) {
        toast.error(err.response?.data?.error || "Error fetching leads");
      } finally {
        fetchPayments();
      }
    };

    fetchLeads();
  }, [navigate]);

  /* ================= LEADS CHART ================= */

  const monthlyLeadData = {};

  Object.keys(leadsData[leadYear] || {}).forEach((month) => {
    const monthNumber = Number(month);

    if (!monthlyLeadData[monthNumber]) {
      monthlyLeadData[monthNumber] = {
        totalLeads: 0,
        approvedLeads: 0,
        duplicateLeads: 0,
        label: dayjs(`${leadYear}-${month}-01`).format("MMM"),
      };
    }

    monthlyLeadData[monthNumber].totalLeads +=
      leadsData[leadYear][month].total || 0;

    monthlyLeadData[monthNumber].approvedLeads +=
      leadsData[leadYear][month].approved || 0;

    monthlyLeadData[monthNumber].duplicateLeads +=
      leadsData[leadYear][month].duplicate || 0;
  });

  const filteredLeadHistory = Object.values(monthlyLeadData).sort(
    (a, b) =>
      dayjs(`${leadYear}-${a.label}`, "YYYY-MMM").month() -
      dayjs(`${leadYear}-${b.label}`, "YYYY-MMM").month()
  );

  const leadStatusData = {
    labels: filteredLeadHistory.map((item) => item.label),
    datasets: [
      {
        label: "Total Leads",
        data: filteredLeadHistory.map((item) => item.totalLeads),
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Approved Leads",
        data: filteredLeadHistory.map((item) => item.approvedLeads),
        backgroundColor: "#19875475",
        borderRadius: 8,
      },
      {
        label: "Duplicate Leads",
        data: filteredLeadHistory.map((item) => item.duplicateLeads),
        backgroundColor: "#dc354575",
        borderRadius: 8,
      },
    ],
  };

  const leadStatusOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { position: "top" } },
    scales: { x: { ...commonGrid }, y: { beginAtZero: true, ...commonGrid } },
  };

  const goToPreviousLeadYear = () => setLeadYear((prev) => prev - 1);
  const goToNextLeadYear = () => setLeadYear((prev) => prev + 1);

  /* ================= PAYMENTS CHART ================= */

  const paymentsYearData = paymentsData[paymentsYear] || {};
  const clientYearData = clientDataByYear[paymentsYear] || {};

  let monthsArray = Object.keys(paymentsYearData)
    .map(Number)
    .sort((a, b) => a - b);

  if (selectedMonth !== "all") {
    monthsArray = monthsArray.filter(
      (m) => m === Number(selectedMonth)
    );
  }

  const paymentLabels = monthsArray.map((m) =>
    selectedMonth === "all"
      ? dayjs(`${paymentsYear}-${m}-01`).format("MMM YYYY")
      : dayjs(`${paymentsYear}-${m}-01`).format("MMM")
  );

  const clientData = monthsArray.map((m) => clientYearData[m] || 0);
  const paymentData = monthsArray.map(
    (m) => paymentsYearData[m]?.payments || 0
  );

  const commissionData = paymentData.map((amt) =>
    Number(((amt * 10) / 100).toFixed(0))
  );

  const mergedChartData = {
    labels: paymentLabels,
    datasets: [
      {
        label: "Clients Converted",
        data: clientData,
        backgroundColor: "#0d6efd65",
        yAxisID: "yClients",
        borderRadius: 8,
      },
      {
        label: "Payments (₹)",
        data: paymentData,
        backgroundColor: "#19875475",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
      {
        label: "Commission (10%)",
        data: commissionData,
        backgroundColor: "#ffc10775",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
    ],
  };

  const mergedChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { position: "top" } },
    scales: {
      x: { ...commonGrid },
      yClients: {
        type: "linear",
        position: "left",
        beginAtZero: true,
        ...commonGrid,
      },
      yAmount: {
        type: "linear",
        position: "right",
        beginAtZero: true,
        grid: { drawOnChartArea: false },
      },
    },
  };

  return (
    <div className="container py-3">
      <h4 className="fw-bold">Welcome, Admin</h4>
      <small>
        Last Updated: {dayjs(new Date()).format("DD MMM YYYY, hh:mm A")}
      </small>

      {/* Charts Row */}
      <div className="row pt-3 g-3">
        <div className="col-lg-6 col-12">
          <div className="border rounded p-3 bg-body">
            <div className="d-flex justify-content-between">
              <h6 className="fw-bold">Leads ({leadYear})</h6>
              <div>
                <button onClick={goToPreviousLeadYear}>◀</button>
                <button onClick={goToNextLeadYear}>▶</button>
              </div>
            </div>
            <div style={{ minHeight: "300px" }}>
              <Bar data={leadStatusData} options={leadStatusOptions} />
            </div>
          </div>
        </div>

        <div className="col-lg-6 col-12">
          <div className="border rounded p-3 bg-body">
            <div className="row g-2">
              <div className="col-6">
                <select
                  className="form-select form-select-sm"
                  value={paymentsYear}
                  onChange={(e) =>
                    setPaymentsYear(Number(e.target.value))
                  }
                >
                  {Object.keys(paymentsData).map((year) => (
                    <option key={year} value={year}>
                      {year}
                    </option>
                  ))}
                </select>
              </div>

              <div className="col-6">
                <select
                  className="form-select form-select-sm"
                  value={selectedMonth}
                  onChange={(e) =>
                    setSelectedMonth(e.target.value)
                  }
                >
                  <option value="all">All Months</option>
                  {(() => {
                    const currentYear = new Date().getFullYear();
                    const currentMonth = new Date().getMonth();
                    const monthsToShow =
                      paymentsYear < currentYear
                        ? 12
                        : currentMonth + 1;

                    return Array.from({
                      length: monthsToShow,
                    }).map((_, i) => (
                      <option key={i} value={i + 1}>
                        {dayjs(
                          `${paymentsYear}-${i + 1}-01`
                        ).format("MMM")}
                      </option>
                    ));
                  })()}
                </select>
              </div>
            </div>

            <div style={{ minHeight: "300px" }}>
              {paymentLabels.length ? (
                <Bar
                  data={mergedChartData}
                  options={mergedChartOptions}
                />
              ) : (
                <div className="text-center text-muted pt-5">
                  No data available
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
